- (void)sendCommand:(XPTBoxCommand)cmd{
    if(CTMediator.isSDK2ndCar) {
        @weakify(self)
        [XPVehicleExt getUrgentWifiKeyTokenWithCmd:(NSInteger)cmd completeBlock:^(NSString * token) {
            @strongify(self)
            [self dealWithSendStr:token];
        }];
        return;
    }
    if([XPBLEKeyManager.instance checkIsNoneVerifySettingWithVin:CTMediator.vin]) {
        //设置了免生物识别
        DLogTagInfo(kFileTransferUrgentTag, @"设置了免生物识别");
        if([XPBLEKeyManager.instance checkIsCertKeyCreatedWithVin:CTMediator.vin uid:CTMediator.uid]) {
            if([CertKeyMessage countWithVin:CTMediator.vin] > 0) {
                DLogTagInfo(kFileTransferUrgentTag, @"存在证书钥匙，且证书钥匙报文大于0");
                [self sendCertKeyCommand:cmd];
            } else {
                DLogTagInfo(kFileTransferUrgentTag, @"存在证书钥匙，但证书钥匙报文为0，尝试使用安全钥匙");
                if(XPBLEKeyManager.instance.defaultCard && [XPBLEKeyManager.instance.defaultCard isValid]) {
                    DLogTagInfo(kFileTransferUrgentTag, @"存在安全钥匙");
                    [self sendSafeKeyCommand:cmd];
                } else {
                    DLogTagError(kFileTransferUrgentTag, @"不存在安全钥匙");
                    [self showError];
                }
            }
        } else if(XPBLEKeyManager.instance.defaultCard && [XPBLEKeyManager.instance.defaultCard isValid]) {
            DLogTagInfo(kFileTransferUrgentTag, @"不存在证书钥匙, 存在安全钥匙, 尝试使用安全钥匙");
            [self sendSafeKeyCommand:cmd];
        } else {
            [self showError];
            DLogTagError(kFileTransferUrgentTag, @"安全钥匙和证书钥匙都不存在，不发送蓝牙指令");
        }
    } else {
        //没有设置免生物识别
        DLogTagInfo(kFileTransferUrgentTag, @"没有设置免生物识别");
        if(XPBLEKeyManager.instance.defaultCard && [XPBLEKeyManager.instance.defaultCard isValid]) {
            DLogTagInfo(kFileTransferUrgentTag, @"存在安全钥匙");
            [self sendSafeKeyCommand:cmd];
        } else if([XPBLEKeyManager.instance checkIsCertKeyCreatedWithVin:CTMediator.vin uid:CTMediator.uid]) {
            DLogTagInfo(kFileTransferUrgentTag, @"不存在安全钥匙，但存在证书钥匙，尝试使用证书钥匙");
            if([CertKeyMessage countWithVin:CTMediator.vin] > 0) {
                DLogTagInfo(kFileTransferUrgentTag, @"证书钥匙报文大于0");
                [self sendCertKeyCommand:cmd];
            } else {
                DLogTagError(kFileTransferUrgentTag, @"证书钥匙报文为0");
                [self showError];
            }
        } else {
            DLogTagError(kFileTransferUrgentTag, @"安全钥匙和证书钥匙都不存在，不发送蓝牙指令");
            [self showError];
        }
    }
}

